import { LinkedList } from './LinkedList';

export class Queue<T> extends LinkedList<T> {
  get front() {
    return this.head;
  }

  enqueue(...vals: T[]) {
    for (let i = 0; i < vals.length; i++) {
      this.append(vals[i]);
    }
  }

  dequeue(): T | null {
    return this.removeHead();
  }
}
